INSERT INTO public.site_content (id, content, type) VALUES
('site-hero-title', 'En avant pour une nouvelle année de notre mieux, <em>sous le regard de Dieu !</em>', 'text'),
('site-hero-desc', 'Une école à taille humaine au cœur de Poitiers, pour l''épanouissement intégral de chaque enfant.', 'text'),
('dynamic-ecole-content', '<p><strong>Nos cahiers :</strong> La bonne tenue du cahier est de rigueur. C’est parfois un travail de longue haleine, mais quelle victoire que d’être capable de présenter une page de cahier propre et jolie ! Le stylo plume aide à une belle écriture, l’assiduité et la volonté font le reste : tout ne sera pas toujours parfait, mais peu importe, l’essentiel est bien de faire de son mieux et de viser un but.</p>
                <p><strong>Nos activités :</strong> Des expériences scientifiques amusantes et variées, des cours d’histoire mis en scène, la découverte de la nature avec nos cinq sens, des bricolages nous permettant de découvrir toute une variété de matériaux et d’outils, voilà nos petits projets mis en place l’après-midi.</p>', 'text'),
('dynamic-projet-content', '<p>L’école Sainte Faustine dispense un enseignement conforme aux programmes de l’Éducation Nationale. Les enseignants appliquent des méthodes de travail privilégiant l’analyse, la structuration de la pensée et le développement de la mémoire, avec des méthodes classiques (syllabique en lecture, chronologique en histoire et descriptive en géographie).</p>
                
                <h3 style="color: var(--primary); font-family: ''Playfair Display'', serif; margin-top: 1.5rem; margin-bottom: 0.5rem;">1/ Formation intellectuelle</h3>
                <ul style="margin-left: 2rem; margin-bottom: 1.5rem;">
                    <li><strong>Lecture et écriture :</strong> L’apprentissage de la lecture commence dès la maternelle simultanément à celui de l’écriture suivant une méthode exclusivement syllabique et phonomimique. Jusqu’à la fin du primaire, ces apprentissages sont perfectionnés grâce à des exercices quotidiens de graphisme, de copie et de lecture.</li>
                    <li><strong>Français :</strong> L’acquisition de l’orthographe se fait par la pratique de dictées. Les textes sont choisis pour élever l’esprit des enfants. Parallèlement, l’enseignant donne des exercices d’analyse grammaticale et logique, de conjugaison et de grammaire. Les enfants apprennent également à composer des rédactions soignées.</li>
                    <li><strong>Mathématiques :</strong> Leur étude développe le raisonnement (problèmes), la mémoire (calcul mental) et le soin (géométrie). Toute règle ou propriété est expliquée et démontrée avant d’être appliquée.</li>
                    <li><strong>Matières d’éveil :</strong> L’enseignement de l’histoire est chronologique, celui de la géographie descriptif et physique. Les sciences naturelles ou « leçons de choses » développent la capacité d’émerveillement de l’enfant.</li>
                    <li><strong>Anglais :</strong> Les élèves ont une séance d''anglais hebdomadaire du CP au CM2.</li>
                </ul>

                <h3 style="color: var(--primary); font-family: ''Playfair Display'', serif; margin-top: 1.5rem; margin-bottom: 0.5rem;">2/ Formation spirituelle</h3>
                <p>L’école Sainte Faustine est une école catholique romaine. Le catéchisme pratiqué est un enseignement complet fondé sur les quatre piliers traditionnels de la catéchèse.</p>', 'text'),
('dynamic-racines-content', '<p>L’école Sainte Faustine a été créée en 2012 sous l’impulsion de familles catholiques souhaitant offrir à leurs enfants une formation scolaire de qualité, basée sur des méthodes reconnues et une approche personnalisée. De 12 élèves la première année, l’effectif de l’école est désormais de 30 à 35 élèves répartis en 3 classes multi-niveaux. Notre chère école a soufflé ses 10 bougies à la rentrée 2022 et a fêté cela dans la joie des retrouvailles en juin 2023.</p>', 'text'),
('dynamic-institutrices-content', '<p>Notre corps professoral est composé d''institutrices passionnées, choisies tant pour leurs compétences académiques que pour leurs qualités humaines et leur adhésion pleine et entière au projet de l''école.</p>
                <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 2rem; margin-top: 2rem;">
                    <div style="background: white; padding: 1.5rem; border-radius: 8px; box-shadow: 0 4px 6px rgba(0,0,0,0.05); border: 1px solid #e2e8f0;">
                        <h3 style="color: var(--primary); margin-bottom: 0.5rem; font-family: ''Playfair Display'', serif;">Marie d''AREXY</h3>
                        <p style="font-weight: 500; font-size: 0.95rem; color: var(--secondary); margin-bottom: 0.5rem;">Directrice de l''établissement</p>
                        <p style="font-size: 0.95rem;">Contact : <a href="mailto:direction.pedagogique@ecolesaintefaustine.fr">direction.pedagogique@ecolesaintefaustine.fr</a> - 06 27 57 62 57</p>
                    </div>
                    <div style="background: white; padding: 1.5rem; border-radius: 8px; box-shadow: 0 4px 6px rgba(0,0,0,0.05); border: 1px solid #e2e8f0;">
                        <h3 style="color: var(--primary); margin-bottom: 0.5rem; font-family: ''Playfair Display'', serif;">Isabelle SAUER</h3>
                        <p style="font-size: 0.95rem;">Maîtresse des classes de maternelle</p>
                    </div>
                    <div style="background: white; padding: 1.5rem; border-radius: 8px; box-shadow: 0 4px 6px rgba(0,0,0,0.05); border: 1px solid #e2e8f0;">
                        <h3 style="color: var(--primary); margin-bottom: 0.5rem; font-family: ''Playfair Display'', serif;">Constance CHARROT</h3>
                        <p style="font-size: 0.95rem;">Maîtresse des classes de CP et CE1</p>
                    </div>
                    <div style="background: white; padding: 1.5rem; border-radius: 8px; box-shadow: 0 4px 6px rgba(0,0,0,0.05); border: 1px solid #e2e8f0;">
                        <h3 style="color: var(--primary); margin-bottom: 0.5rem; font-family: ''Playfair Display'', serif;">Céline d''HARDEMARE</h3>
                        <p style="font-size: 0.95rem;">Maîtresse des classes des CE2, CM1 et CM2</p>
                    </div>
                </div>', 'text'),
('dynamic-direction-content', '<p>La direction pédagogique de l''école garantit la fidèle application du projet éducatif et l''harmonie au sein de l''établissement.</p>
                <div style="background: white; padding: 1.5rem; border-radius: 8px; box-shadow: 0 4px 6px rgba(0,0,0,0.05); border: 1px solid #e2e8f0; margin-top: 2rem;">
                    <h3 style="color: var(--primary); margin-bottom: 0.5rem; font-family: ''Playfair Display'', serif;">Marie d''AREXY</h3>
                    <p style="font-weight: 500; font-size: 0.95rem; color: var(--secondary); margin-bottom: 0.5rem;">Directrice de l''établissement</p>
                    <p style="font-size: 0.95rem;">Contact : <a href="mailto:direction.pedagogique@ecolesaintefaustine.fr">direction.pedagogique@ecolesaintefaustine.fr</a> - 06 27 57 62 57</p>
                </div>
                <div style="background: white; padding: 1.5rem; border-radius: 8px; box-shadow: 0 4px 6px rgba(0,0,0,0.05); border: 1px solid #e2e8f0; margin-top: 1rem;">
                    <h3 style="color: var(--primary); margin-bottom: 0.5rem; font-family: ''Playfair Display'', serif;">L''équipe de gestion</h3>
                    <p style="font-size: 0.95rem;">L’école est gérée par l’association ASOCEP (Action Sociale Citoyenne Educative du Poitou), présidée par <strong>Monsieur Clément DECROIX</strong>.</p>
                </div>', 'text'),
('dynamic-locaux-content', '<p><strong>Adresse :</strong> Ecole Sainte Faustine, 12 place Henri Barbusse - Forum Rivaud - 86000 POITIERS.</p>
                <p>L''école est situé dans le quartier Rivaud à Poitiers.</p>', 'text'),
('dynamic-tarifs-content', '<p>Placée sous la protection de la Miséricorde divine, l’école Sainte Faustine accueille les enfants de la toute petite section au CM2.</p>
                            
                            <h3>Modalités d''inscription (Rentrée 2026/2027)</h3>
                            <ul>
                                <li><strong>Dépôt du dossier :</strong> Le dossier d''inscription complet est à déposer avant le <strong>20 avril 2026</strong>.</li>
                                <li><strong>Adresse d''envoi :</strong> 12 place Henri Barbusse, 86000 POITIERS.</li>
                                <li><strong>Admission :</strong> L''admission est prononcée en fonction de la date de réception du dossier complet et des places disponibles. Un entretien avec les parents et une demi-journée d''évaluation pour l''enfant peuvent être requis.</li>
                            </ul>
                            <a href="inscription.html" class="btn btn-primary btn-outline" style="margin-top: 1rem;">Aller sur la page</a>

                            <h3>Tarifs de scolarité</h3>
                            <div class="highlight-box">
                                <p><strong>Frais de dossier :</strong> 50 € par famille (non remboursables en cas d''annulation).</p>
                                <p><strong>Frais de fournitures et d''assurance :</strong> 60 € par enfant par an.</p>
                            </div>
                            
                            <p>Afin de pourvoir aux charges de l’école (loyer, salaires, charges sociales, etc.), nous proposons un modèle de contribution :</p>
                            <ul>
                                <li><strong>Contribution de soutien :</strong> 260 € (Grâce à la déduction fiscale de 66%, le coût de revient net d''impôt est de 88,40 €).</li>
                            </ul>
                            
                            <h3>Bourses et Solidarité</h3>
                            <p>Les difficultés financières ne doivent pas être un obstacle à l''inscription de votre enfant. Des bourses peuvent être demandées :</p>
                            <ul>
                                <li>Auprès de l''<strong>AES</strong> (Association Education Solidarité).</li>
                                <li>Sur le fonds de solidarité propre à notre école.</li>
                            </ul>
                            <p><strong>Contact :</strong> presidence.asso@ecolesaintefaustine.fr ou par téléphone au 07 82 87 39 86.</p>', 'text'),
('dynamic-horaires-content', '<h3>Organisation de la semaine</h3>
                            <p>Les enfants ont classe les lundis, mardis, jeudis et vendredis.</p>
                            
                            <table class="schedule-table">
                                <tr>
                                    <th>Moment de la journée</th>
                                    <th>Horaires</th>
                                </tr>
                                <tr>
                                    <td><strong>Matin</strong></td>
                                    <td>8h30 - 12h00</td>
                                </tr>
                                <tr>
                                    <td><strong>Après-midi</strong></td>
                                    <td>13h30 - 16h15</td>
                                </tr>
                            </table>

                            <h3>Déroulement de la journée</h3>
                            <ul>
                                <li><strong>8h15 :</strong> Accueil échelonné des élèves au Forum Rivaud.</li>
                                <li><strong>8h30 :</strong> Rassemblement dans le silence pour la prière avec toute l’équipe enseignante (les parents y sont fraternellement invités).</li>
                                <li><strong>8h45 - 12h00 :</strong> Temps d''enseignement.</li>
                                <li><strong>13h20 :</strong> Accueil dans la cour.</li>
                                <li><strong>13h30 - 16h15 :</strong> Reprise et temps d''enseignement de l''après-midi.</li>
                            </ul>

                            <h3>Pause-déjeuner (Cantine)</h3>
                            <div class="highlight-box">
                                <p><i class="ph ph-info"></i> L’école ne dispose <strong>pas de cantine</strong>.</p>
                            </div>
                            <p>Les enfants qui ne peuvent pas rentrer chez eux, peuvent déjeuner sur place avec un <strong>"panier-repas"</strong> préparé à la maison, qu''ils peuvent réchauffer. Une participation financière est demandée aux parents pour les frais de surveillance du temps de repas.</p>

                            <h3>Garderie (Périscolaire)</h3>
                            <p>Actuellement, l''école ne propose <strong>pas de garderie périscolaire</strong>. Toutefois, en cas de besoin spécifique, l''équipe se tient à l''écoute des familles pour étudier des solutions ponctuelles.</p>', 'text'),
('dynamic-tenue-content', '<p>L''école Sainte Faustine demande à ses élèves de porter une tenue vestimentaire adaptée à un lieu d''étude et d''éducation.</p>
                            <ul>
                                <li><strong>Filles :</strong> blouse ou tablier pour les activités salissantes, tenue classique et décente (jupes ou robes arrivant au genou).</li>
                                <li><strong>Garçons :</strong> tenue classique (pas de pantalons troués ni de joggings en dehors des séances de sport).</li>
                            </ul>
                            <p>Le port de la blouse est recommandé pour les activités manuelles et artistiques afin de protéger les vêtements.</p>', 'text')
ON CONFLICT (id) DO UPDATE SET content = EXCLUDED.content;